import java.io.*;
import java.util.HashMap;
import java.util.Map;

public class DiskCache {
    private static final String CACHE_DIR = "cache/";
    private Map<String, Object> cache;

    public DiskCache() {
        cache = new HashMap<>();
        loadCache();
    }

    public <T> T get(String key, Class<T> clazz) throws IOException, ClassNotFoundException {
        if (cache.containsKey(key)) {
            return clazz.cast(cache.get(key));
        }
        File file = new File(CACHE_DIR + key);
        if (file.exists()) {
            try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(file))) {
                T value = clazz.cast(ois.readObject());
                cache.put(key, value);
                return value;
            }
        }
        return null;
    }

    public <T> void put(String key, T value) throws IOException {
        cache.put(key, value);
        File file = new File(CACHE_DIR + key);
        try (ObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream(file))) {
            oos.writeObject(value);
        }
    }

    private void loadCache() {
        File dir = new File(CACHE_DIR);
        if (!dir.exists()) {
            return;
        }
        for (File file : dir.listFiles()) {
            if (file.isFile()) {
                try {
                    String key = file.getName();
                    Object value = get(key, Object.class);
                    cache.put(key, value);
                } catch (IOException | ClassNotFoundException e) {
                    e.printStackTrace();
                }
            }
        }
    }

    public void clear() {
        cache.clear();
        File dir = new File(CACHE_DIR);
        if (dir.exists()) {
            for (File file : dir.listFiles()) {
                file.delete();
            }
        }
    }
}